import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"0.全集中呼吸法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/0.全集中呼吸法.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/0.全集中呼吸法.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/0.全集中呼吸法.md"};function _(d,a,l,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"_0-全集中呼吸法",tabindex:"-1"},[n("0.全集中呼吸法 "),e("a",{class:"header-anchor",href:"#_0-全集中呼吸法","aria-label":'Permalink to "0.全集中呼吸法"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),s('<h1 id="全集中呼吸法" tabindex="-1">全集中呼吸法 <a class="header-anchor" href="#全集中呼吸法" aria-label="Permalink to &quot;全集中呼吸法&quot;">​</a></h1><p>全集中呼吸法</p><p>出自《鬼灭之刃》，继国缘壹所钻研出，为了以人类之身对抗鬼而创造的技巧的通称。其主要效果是用来增强身体素质，尤其是擅长通过心肺功能的强化进行短暂的爆发。</p><p>呼吸法初级训练<br> 500<br> 效果：由呼吸中感受到的，是一种奇特的感觉。</p><p>你开启刻度槽：呼吸法，其上限等于耐力+决心，呼吸法初始为0点，每场战斗结束时，将你的呼吸法归零。</p><p>每个训练者的回合开始时，只要训练者能够进行呼吸就回复耐力点的呼吸法。</p><p>当你在战斗中消耗的呼吸法大于训练者三倍耐力属性时，本场景内你进入【呼吸耗竭】阶段。</p><p>训练者处于【呼吸耗竭】阶段时，其回合结束时需要进行一次强韧豁免，其DC=本场景内消耗呼吸法的数量，失败则获得差值的C级创伤来源的疲乏点数，持续一场景。</p><p>当训练者处于【呼吸耗竭】阶段时，保持两个回合没有使用需要消耗呼吸法的能力，则退出【呼吸耗竭】阶段直到再次达到进入【呼吸耗竭】阶段的前提。</p><p>当你无法呼吸时，你进入【呼吸过载】状态直到你能够再次呼吸。<br> （例如：处于没有空气的真空环境，在没有水中呼吸类能力时被水包裹。注意：无需呼吸无法让你在无法呼吸的环境里强行呼吸。）</p><p>训练者处于【呼吸过载】状态时，训练者只能最多使用等同其传奇耐力次需要消耗呼吸法的能力，离开该状态时重置。</p><p>呼吸法基础用法：消耗2点呼吸法加快身体活动，使用者本回合的生理相关检定获得1点增强加值</p><p>前置：呼吸法初级训练<br> 全集中呼吸-常中<br> D+750<br> 效果：<br> 全天候持续进行全集中呼吸的状态，甚至睡觉时候也能够保持。</p><p>每次进入战斗时，训练者获得等同于你呼吸法上限一半的呼吸法，进入【呼吸耗竭】阶段的前提现在改为训练者在战斗中消耗大于等同于训练者耐力六倍的呼吸法。</p><p>每时每刻都在保持呼吸法的运行会不断的增强训练者的身体状态，在一场影片结束后，训练者获得1点生理相关检定上的修行加值，每以此获得3点修行加值，你便在强韧豁免上获得2点内在加值。</p><p>该资源如常提供内在属性点</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=r(o,[["render",_]]);export{f as __pageData,m as default};
